{
  "name": "Delaware Senior Medicare Patrol (SMP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Medicare beneficiaries, families, and caregivers regardless of income[2][3]",
    "asset_limits": "No asset limits or tests apply[2][3]",
    "other_requirements": ["Must be a Medicare beneficiary (age 65+, younger with disabilities or ESRD), family member, or caregiver; no other restrictions[2][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Outreach, education, and counseling to prevent, detect, and report Medicare fraud, errors, and abuse; community awareness presentations, health fairs, one-on-one counseling, advocacy to resolve billing disputes, referrals to investigators; often includes SHIP health insurance counseling[2][7]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Use national SMP Locator at 877-808-2468 to find Delaware contact[4]", "Online: SMP Locator at smpresource.org to locate Delaware SMP[2][4]", "In-person or local contact: Administered by Delaware DHSS Division of Services for Aging and Adults with Physical Disabilities (DSAAPD)[7][9]"],
    "processing_time": "No formal application or processing time; services provided upon contact for education/counseling[2]",
    "waitlist": null,
    "forms": ["No specific forms required for service access[2]"],
    "documents": ["Medicare card or number if reporting suspected fraud; no documents needed for general education/outreach[2][9]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to Delaware Medicare beneficiaries statewide[7][9]",
    "regional_variations": null,
    "offices_or_providers": ["Administered statewide by Delaware DHSS DSAAPD; use SMP Locator for local contacts[7][9]"]
  },
  "official_source": "https://dhss.delaware.gov/dsaapd (Delaware DHSS DSAAPD administers); national https://smpresource.org[2][7][9]",
  "gotchas": ["Not a financial assistance or healthcare benefits program—focuses solely on fraud prevention/education, not direct aid or eligibility for other benefits; often confused with SHIP (which it may co-provide); volunteers deliver services, not paid staff; report fraud promptly to avoid identity theft[2][7][9]"],
  "data_shape_notes": "no income/asset/age test for beneficiaries; volunteer-based education/advocacy service only; no enrollment or waitlist—immediate access via contact; integrates with SHIP counseling[2][3][7]"
}

{
  "name": "CARE Delaware Caregiver Support Program",
  "eligibility": {
    "age": 18,
    "income_limits": "Varies by specific service within the program; financial eligibility required for services like respite care, aligned with Delaware Medicaid thresholds (e.g., household income at or below 100% Federal Poverty Level for full Medicaid, higher for specific groups like children/pregnant women up to 200% FPL). No exact dollar table provided in sources; contact CARE Delaware for current amounts by household size[3][7].",
    "asset_limits": "Financial resources must be under certain limits for long-term care programs (specific to Medicaid-linked services); details not quantified. Primary residence and certain assets may be exempt in Medicaid spend-down scenarios[5][7].",
    "other_requirements": [
      "Care recipient: Delaware residents aged 18+ with physical/mental impairments needing supervision/support in activities of daily living (ADLs) such as bathing, dressing, toileting, feeding, mobility[3].",
      "Caregiver: Adults 18+ providing care; special populations include adults 55+ caring for non-child adults 18+ with developmental disabilities, or grandparents/relatives 55+ caring for children 18 and under[1][3].",
      "Medical need: Assistance with at least 1-2 ADLs; functional impairment[3][5][6]."
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Respite services (in-home or nursing home, regular or occasional); caregiver skills training; support groups; needs assessment and care planning; case management. No specific dollar amounts or hours per week stated; tailored via care plan[3].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Phone: 800.223.9074 (DSAAPD or Joining Generations)[3]",
      "Website: www.dhss.delaware.gov/dsaapd[3]"
    ],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": [],
    "documents": [
      "Proof of residency, income, assets (for financial eligibility); medical documentation of ADL needs; ID/background check may be required for caregivers[3][6][7]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Delaware residents only[3][7]",
    "regional_variations": "Eligibility and services may vary by program component; statewide resource centers, but contact local DSAAPD for assistance. No specific county differences noted[3].",
    "offices_or_providers": ["DSAAPD (statewide), Joining Generations[3]"]
  },
  "official_source": "https://www.dhss.delaware.gov/dsaapd",
  "gotchas": [
    "Eligibility varies by specific service (e.g., respite vs. training); not all caregivers qualify for all benefits—must contact for assessment[3].",
    "Financial/medical eligibility tied to Medicaid criteria; asset spend-down required but protectable (consult elder law expert)[5].",
    "Not a paid caregiver program; focuses on support/respite, unlike VA PCAFC or family pay programs[2][6].",
    "Special populations (e.g., grandparents 55+) have distinct rules[1]."
  ],
  "data_shape_notes": "Eligibility requirements vary by program/service; no fixed income/asset tables—requires direct contact; statewide but assessment-driven; linked to DSAAPD for physically/mentally impaired adults 18+[3]"
}

{
