    "waitlist": null,
    "forms": ["Senior Citizens Affordable Taxi Application (SCAT)[1][6]"],
    "documents": ["Application with professional certification for disability if applicable; photo ID taken in-person post-approval; applicant expense for ID trip[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Statewide in Delaware; must use participating taxi companies[1][2][3][5]",
    "regional_variations": "Photo ID offices in Wilmington and Dover only; taxi fares set by individual companies (potential regional fare differences); no specified wait time or provider variations[1]",
    "offices_or_providers": ["DTC administrative offices: 400 S. Madison St, Wilmington; 900 Public Safety Blvd, Dover[1]", "Participating taxi companies (call nearest one)[1][5]"]
  },
  "official_source": "http://www.dartfirststate.com/scat/",
  "gotchas": ["Must purchase SCAT tickets separately after approval; present Photo ID each ride or denied service[1]", "Certification solely based on application criteria; DTC may verify with certifiers[1]", "Fees for application completion not covered by DTC[1]", "Exclusions for certain conditions like addiction or contagious diseases[1]", "Applicant pays for trip to get Photo ID[1]", "Only participating taxi companies accepted[5]"],
  "data_shape_notes": "No income or asset test; eligibility purely age 65+ or certified disability preventing driving; ticket-based discount system requiring in-person ID issuance at 2 statewide offices; exclusions for specific health risks"
}

